      "fraction_bars_make_equivalence_visible": "💡 Fraction bars make equivalence VISIBLE: highlight 1/2 of the halves bar and 3/6 of the sixths bar — they cover the same length. Same fraction.",
      "click_to_remove_2": "Click to remove",
      "x_square": "+x² (square)",
      "x_square_dashed": "−x² (square, dashed)",
      "tile_palette_click_to_add": "Tile palette (click + to add):",
      "add": "+ Telh",
